// All endpoints: POST https://api.velt.dev/v2/workflow/<resource>/<action>
// Required headers on every request:
//   x-velt-api-key: <workspace API key>
//   x-velt-auth-token: <short-lived auth token>
//   content-type: application/json
// Request envelope: { "data": { ...fields } }
// Success envelope: { "result": { ...fields } }
// Error envelope: { "error": { "message": "...", "status": "INVALID_ARGUMENT", "details": {} } }

// ── DEFINITIONS ──────────────────────────────────────────────────────────────
// POST /v2/workflow/definitions/create
// Body fields: definitionId (string, required), name (string, required),
//   description (string), scope ({ level: 'apiKey'|'organization'|'document',
//   organizationId?, documentId? }), nodes (array, required), edges (array, required),
//   groups (array), triggers (array), tags (string[]), custom (object)
// Node shape: { nodeId, type: 'agent'|'human'|'webhook', config, slaMs? }
//   agent config: { agentId, promptOverride?, inputMapping?, blocking?, resolutionPolicy?, agentMaxRuntimeMs?, requireNonEmptyOutput? }
//   human config: { reviewers: [{ userId, mandatory }], commentBody? }  -- use reviewers[], not legacy reviewerIds[]
// Edge shape: { from, to, when? }  -- when is a gating expression evaluated at runtime
// Group shape: { groupId, memberNodeIds, expectedSteps, quorum, onQuorumMet?: 'waitAll'|'cancelOnQuorum'|'joinOnQuorum', requiredNodeIds? }
// Response: { result: { definitionId, version, ... } }

// POST /v2/workflow/definitions/update
// Body fields: definitionId (required) + same optional fields as create
// Supports ifVersion (integer) for optimistic-lock updates
// Each update increments version; in-flight executions are immune to changes

// POST /v2/workflow/definitions/get
// Body fields: definitionId (required)
// Response: { result: DefinitionView }

// POST /v2/workflow/definitions/list
// Body fields: scope?, status?, tags?, cursor?, limit?
// Response: { result: { definitions: DefinitionView[], nextCursor? } }

// POST /v2/workflow/definitions/delete
// Body fields: definitionId (required)
// Rejected (FAILED_PRECONDITION) if the definition has in-flight executions

// ── EXECUTIONS ───────────────────────────────────────────────────────────────
// POST /v2/workflow/executions/dispatch
// Body fields: definitionId (required), idempotencyKey (string, highly recommended),
//   correlationId?, triggerContext?, webhookUrl? (must be https://), webhookSecret?
//   webhookUrl and webhookSecret must be provided together
// Response: { result: { executionId, correlationId, deduplicated: boolean } }
// deduplicated: true means the idempotencyKey was already used — same executionId returned, no duplicate spawned

// POST /v2/workflow/executions/get
// Body fields: executionId (required)
// Response: { result: ExecutionView }  -- includes steps[] array

// POST /v2/workflow/executions/list
// Body fields: definitionId?, status?, cursor?, limit?
// Response: { result: { executions: ExecutionView[], nextCursor? } }

// POST /v2/workflow/executions/cancel
// Body fields: executionId (required), reason? (string)
// Rejected if execution is already terminal

// POST /v2/workflow/executions/getEvents
// Body fields: executionId (required), sinceSeq? (integer)
// Response: { result: { events: ApprovalEventView[] } }
// Use sinceSeq to recover missed webhook events after an outage
// seq values may be non-contiguous (internal-only events fill gaps but are filtered)

// ── STEPS ────────────────────────────────────────────────────────────────────
// POST /v2/workflow/steps/recordReviewerDecision
// Body fields: executionId (required), stepId (required), reviewerId (required),
//   decision: 'approve'|'reject' (required), reason? (string)
// Response: { result: { recorded: boolean, aggregatorStatus: string, resumeScheduled: boolean } }

// POST /v2/workflow/steps/recordAgentResolution
// Body fields: executionId (required), stepId (required), resolutionId (required),
//   output? (object)
// Used for blocking agent steps (blocking: true)

// POST /v2/workflow/steps/cancel
// Body fields: executionId (required), stepId (required), reason? (string)
// Requires admin scope (PERMISSION_DENIED for non-admins)

// POST /v2/workflow/steps/resolve
// Body fields: executionId (required), stepId (required), output? (object)
// Admin-level override to force-complete a step

// ── WEBHOOK EVENTS DELIVERED TO webhookUrl ───────────────────────────────────
// Headers: x-velt-signature (sha256=<hex> HMAC-SHA256 of raw body),
//          x-velt-event-id, x-velt-attempt (0-based)
// Payload: { event, executionId, definitionId, stepId, status?, seq, timestamp, correlationId, data }
// Externally-visible event types:
//   execution.dispatched, execution.completed, execution.failed, execution.cancelled
//   step.awaiting-approval, step.completed, step.failed, step.breached, step.cancelled
//   group.quorum-met
// Verify signature: HMAC-SHA256(rawBodyBytes, webhookSecret) — hash raw bytes, not re-serialized JSON
// At-least-once delivery: make receiver idempotent on (executionId, seq)
// Retry schedule: immediate, +2s, +8s, +32s, +2min, +8min → DLQ after 5 retries
